'use client'

import { useEffect, useState } from 'react'
import { createClient } from '@/lib/supabase/client'
import Link from 'next/link'
import RoutesMap from '@/components/map-view'

interface Suggestion {
  place_name: string
  center: [number, number]
}

const supabase = createClient()

async function fetchAllRoutes() {
  // 1. Cargar rutas activas
  const { data: routes, error } = await supabase
    .from('routes')
    .select('id, origin_name, destination_name, departure_time, days_of_week, seats_available, price_per_seat, active, created_at, driver_id')
    .eq('active', true)
    .order('departure_time', { ascending: true })

  if (error) { console.error('Error cargando rutas:', JSON.stringify(error)); return [] }
  if (!routes || routes.length === 0) return []

  // 2. Cargar perfiles de conductores
  const driverIds = [...new Set(routes.map((r: any) => r.driver_id))]
  const { data: profiles } = await supabase
    .from('profiles')
    .select('id, full_name, avatar_url')
    .in('id', driverIds)

  // 3. Cargar geometría de cada ruta (para el mapa)
  const routesWithGeo = await Promise.all(
    routes.map(async (route: any) => {
      const { data: geoData } = await supabase.rpc('get_route_geojson', { route_id: route.id })
      return {
        ...route,
        profiles: (profiles ?? []).find((p: any) => p.id === route.driver_id) ?? null,
        origin_geo:      geoData?.origin_geo      ?? null,
        destination_geo: geoData?.destination_geo ?? null,
        route_line_geo:  geoData?.route_line_geo  ?? null,
      }
    })
  )

  return routesWithGeo
}

export default function RoutesListPage() {
  const [routes, setRoutes] = useState<any[]>([])
  const [filteredRoutes, setFilteredRoutes] = useState<any[]>([])
  const [loading, setLoading] = useState(true)

  const [searchOriginName, setSearchOriginName] = useState('')
  const [searchDestName, setSearchDestName] = useState('')
  const [searchTime, setSearchTime] = useState('')

  const [originSuggestions, setOriginSuggestions] = useState<Suggestion[]>([])
  const [destSuggestions, setDestSuggestions] = useState<Suggestion[]>([])
  const [showOriginSuggestions, setShowOriginSuggestions] = useState(false)
  const [showDestSuggestions, setShowDestSuggestions] = useState(false)

  const MAPBOX_TOKEN = process.env.NEXT_PUBLIC_MAPBOX_ACCESS_TOKEN

  useEffect(() => {
    fetchAllRoutes().then(data => {
      setRoutes(data)
      setFilteredRoutes(data)
      setLoading(false)
    })
  }, [])

  useEffect(() => {
    filterRoutes()
  }, [routes, searchOriginName, searchDestName, searchTime])

  const searchMapbox = async (query: string, type: 'origin' | 'dest') => {
    if (query.length < 3) {
      type === 'origin' ? setOriginSuggestions([]) : setDestSuggestions([])
      return
    }
    try {
      const res = await fetch(
        `https://api.mapbox.com/geocoding/v5/mapbox.places/${encodeURIComponent(query)}.json?country=ES&proximity=-15.5,28.3&bbox=-18.5,27.5,-13.0,29.5&access_token=${MAPBOX_TOKEN}`
      )
      const data = await res.json()
      if (type === 'origin') { setOriginSuggestions(data.features || []); setShowOriginSuggestions(true) }
      else { setDestSuggestions(data.features || []); setShowDestSuggestions(true) }
    } catch (e) { console.error(e) }
  }

  const selectOrigin = (s: Suggestion) => { setSearchOriginName(s.place_name); setShowOriginSuggestions(false) }
  const selectDest   = (s: Suggestion) => { setSearchDestName(s.place_name);   setShowDestSuggestions(false) }

  const clearSearch = () => {
    setSearchOriginName(''); setSearchDestName(''); setSearchTime('')
    setOriginSuggestions([]); setDestSuggestions([])
    setShowOriginSuggestions(false); setShowDestSuggestions(false)
    setFilteredRoutes(routes)
  }

  function timeToMinutes(time: string): number {
    const [h, m] = time.split(':').map(Number)
    return h * 60 + m
  }

  function filterRoutes() {
    if (!searchOriginName && !searchDestName && !searchTime) {
      setFilteredRoutes(routes); return
    }
    setFilteredRoutes(routes.filter(route => {
      const originMatch = !searchOriginName || route.origin_name?.toLowerCase().includes(searchOriginName.toLowerCase())
      const destMatch   = !searchDestName   || route.destination_name?.toLowerCase().includes(searchDestName.toLowerCase())
      const timeMatch   = !searchTime       || Math.abs(timeToMinutes(searchTime) - timeToMinutes(route.departure_time)) <= 30
      return originMatch && destMatch && timeMatch
    }))
  }

  return (
    <div className="min-h-screen bg-gray-50 p-6">
      <div className="max-w-6xl mx-auto">

        {/* Cabecera */}
        <div className="flex justify-between items-center mb-8">
          <div>
            <h1 className="text-3xl font-bold text-blue-900">Rutas en Canarias</h1>
            <p className="text-gray-500">Encuentra tu próximo viaje compartido</p>
          </div>
          <Link href="/routes/create" className="bg-blue-600 text-white px-6 py-3 rounded-xl font-bold hover:bg-blue-700 transition shadow-lg">
            + Publicar ruta
          </Link>
        </div>

        {/* Búsqueda */}
        <div className="bg-white rounded-2xl shadow-lg p-6 mb-8">
          <h2 className="text-lg font-bold text-gray-900 mb-4">🔍 Buscar rutas</h2>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-4">

            {/* Origen */}
            <div className="relative">
              <label className="block text-sm font-medium text-gray-700 mb-2">📍 Desde</label>
              <input type="text" value={searchOriginName}
                onChange={e => { setSearchOriginName(e.target.value); searchMapbox(e.target.value, 'origin') }}
                onFocus={() => originSuggestions.length > 0 && setShowOriginSuggestions(true)}
                onBlur={() => setTimeout(() => setShowOriginSuggestions(false), 200)}
                placeholder="Ej: Las Palmas de Gran Canaria"
                className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
              />
              {showOriginSuggestions && originSuggestions.length > 0 && (
                <div className="absolute z-10 w-full mt-1 bg-white border border-gray-300 rounded-lg shadow-lg max-h-60 overflow-y-auto">
                  {originSuggestions.map((s, i) => (
                    <div key={i} onMouseDown={e => { e.preventDefault(); selectOrigin(s) }}
                      className="px-4 py-3 hover:bg-blue-50 cursor-pointer border-b last:border-b-0 text-sm text-gray-900">
                      {s.place_name}
                    </div>
                  ))}
                </div>
              )}
            </div>

            {/* Destino */}
            <div className="relative">
              <label className="block text-sm font-medium text-gray-700 mb-2">🎯 Hacia</label>
              <input type="text" value={searchDestName}
                onChange={e => { setSearchDestName(e.target.value); searchMapbox(e.target.value, 'dest') }}
                onFocus={() => destSuggestions.length > 0 && setShowDestSuggestions(true)}
                onBlur={() => setTimeout(() => setShowDestSuggestions(false), 200)}
                placeholder="Ej: Agaete"
                className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
              />
              {showDestSuggestions && destSuggestions.length > 0 && (
                <div className="absolute z-10 w-full mt-1 bg-white border border-gray-300 rounded-lg shadow-lg max-h-60 overflow-y-auto">
                  {destSuggestions.map((s, i) => (
                    <div key={i} onMouseDown={e => { e.preventDefault(); selectDest(s) }}
                      className="px-4 py-3 hover:bg-blue-50 cursor-pointer border-b last:border-b-0 text-sm text-gray-900">
                      {s.place_name}
                    </div>
                  ))}
                </div>
              )}
            </div>

            {/* Hora */}
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">🕒 Hora (±30 min)</label>
              <input type="time" value={searchTime} onChange={e => setSearchTime(e.target.value)}
                className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
              />
            </div>
          </div>

          {(searchOriginName || searchDestName || searchTime) && (
            <>
              <div className="flex justify-end mb-2">
                <button onClick={clearSearch} className="text-sm text-blue-600 hover:text-blue-700 font-medium">✕ Limpiar búsqueda</button>
              </div>
              <div className="p-3 bg-blue-50 rounded-lg">
                <p className="text-sm text-blue-900">
                  <span className="font-bold">{filteredRoutes.length}</span> {filteredRoutes.length === 1 ? 'ruta encontrada' : 'rutas encontradas'}
                  {searchTime && <span className="ml-2 text-xs">(±30 minutos de {searchTime})</span>}
                </p>
              </div>
            </>
          )}
        </div>

        {/* Mapa */}
        {!loading && filteredRoutes.length > 0 && (
          <div className="mb-10 h-[450px] w-full rounded-3xl overflow-hidden shadow-xl border-4 border-white relative z-0">
            <RoutesMap routes={filteredRoutes} />
          </div>
        )}

        {/* Lista */}
        {loading ? (
          <div className="flex justify-center items-center h-64 text-blue-600 font-bold text-xl">
            Cargando rutas disponibles...
          </div>
        ) : filteredRoutes.length === 0 ? (
          <div className="text-center py-20 bg-white rounded-2xl shadow-sm border border-dashed border-gray-300">
            <p className="text-gray-500 text-lg">
              {(searchOriginName || searchDestName || searchTime)
                ? 'No se encontraron rutas que coincidan con tu búsqueda'
                : 'No hay rutas publicadas. ¡Sé el primero!'}
            </p>
            {(searchOriginName || searchDestName || searchTime) && (
              <button onClick={clearSearch} className="mt-4 text-blue-600 hover:text-blue-700 font-medium">Ver todas las rutas</button>
            )}
          </div>
        ) : (
          <div className="grid gap-6 md:grid-cols-2 lg:grid-cols-3">
            {filteredRoutes.map(route => (
              <div key={route.id} className="bg-white rounded-2xl shadow-sm border border-gray-100 p-5 hover:shadow-md transition">
                <div className="flex items-center gap-3 mb-4">
                  {route.profiles?.avatar_url
                    ? <img src={route.profiles.avatar_url} alt="" className="w-10 h-10 rounded-full object-cover" />
                    : <div className="w-10 h-10 bg-blue-600 rounded-full flex items-center justify-center text-white font-bold">
                        {route.profiles?.full_name?.charAt(0) ?? '?'}
                      </div>
                  }
                  <div>
                    <p className="font-bold text-gray-800">{route.profiles?.full_name ?? 'Conductor'}</p>
                    <p className="text-[10px] text-blue-500 font-bold uppercase tracking-wider">Conductor</p>
                  </div>
                </div>

                <div className="space-y-3 mb-5">
                  <div className="flex items-start gap-2">
                    <span className="text-lg">📍</span>
                    <div>
                      <p className="text-[10px] text-gray-400 font-bold uppercase">Origen</p>
                      <p className="text-gray-700 font-semibold">{route.origin_name}</p>
                    </div>
                  </div>
                  <div className="flex items-start gap-2">
                    <span className="text-lg">🏁</span>
                    <div>
                      <p className="text-[10px] text-gray-400 font-bold uppercase">Destino</p>
                      <p className="text-gray-700 font-semibold">{route.destination_name}</p>
                    </div>
                  </div>
                </div>

                <div className="flex justify-between items-center border-t pt-4">
                  <div>
                    <p className="text-2xl font-black text-blue-600">{route.departure_time?.substring(0, 5)}</p>
                    <p className="text-[10px] text-gray-400 font-bold uppercase">Salida</p>
                  </div>
                  <div className="text-right">
                    {route.price_per_seat != null
                      ? <><p className="text-xl font-bold text-gray-800">{route.price_per_seat}€</p><p className="text-[10px] text-gray-400 font-bold uppercase">Por plaza</p></>
                      : <><p className="text-xl font-bold text-green-600">Gratis</p><p className="text-[10px] text-gray-400 font-bold uppercase">Sin coste</p></>
                    }
                  </div>
                </div>

                <Link href={`/routes/${route.id}`}
                  className="mt-5 block w-full bg-gray-50 text-gray-800 text-center py-3 rounded-xl font-bold hover:bg-blue-600 hover:text-white transition">
                  Ver detalles →
                </Link>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  )
}